public class OsgiMetaDataScannerService implements ScannerService { private static final Logger logger = WebBeansLoggerFacade . getLogger ( OsgiMetaDataScannerService . class ) ; protected ServletContext servletContext = null ; private static final String META_INF_BEANS_XML = "META-INF/beans.xml" ; private static final String WEB_INF_BEANS_XML = "WEB-INF/beans.xml" ; private Set < Class < ? > > beanClasses = new HashSet < Class < ? > > ( ) ; private Set < URL > beanXMLs = new HashSet < URL > ( ) ; private Set < String > beanArchiveJarNames = new HashSet < String > ( ) ; private Map < String , Set < String > > classAnnotations = new HashMap < String , Set < String > > ( ) ; public void init ( Object object ) { if ( object instanceof ServletContext ) { servletContext = ( ServletContext ) object ; } } public void release ( ) { beanClasses = new HashSet < Class < ? > > ( ) ; beanXMLs = new HashSet < URL > ( ) ; beanArchiveJarNames = new HashSet < String > ( ) ; classAnnotations . clear ( ) ; } public void scan ( ) throws WebBeansDeploymentException { logger . info ( "Using OsgiMetaDataScannerService!" ) ; Bundle mainBundle = BundleUtils . getContextBundle ( true ) ; ServiceReference reference = mainBundle . getBundleContext ( ) . getServiceReference ( PackageAdmin . class . getName ( ) ) ; try { PackageAdmin packageAdmin = ( PackageAdmin ) mainBundle . getBundleContext ( ) . getService ( reference ) ; findBeansXml ( mainBundle , packageAdmin ) ; findBeanClasses ( mainBundle , packageAdmin ) ; } catch ( Exception e ) { throw new WebBeansDeploymentException ( "problem while scanning OSGi bundle" , e ) ; } finally { mainBundle . getBundleContext ( ) . ungetService ( reference ) ; } } private void findBeanClasses ( Bundle mainBundle , PackageAdmin packageAdmin ) { BundleClassFinder bundleClassFinder = new BundleAssignableClassFinder ( packageAdmin , mainBundle , new Class < ? > [ ] { Object . class } , new ClassDiscoveryFilter ( ) { public boolean directoryDiscoveryRequired ( String directory ) { return true ; } public boolean jarFileDiscoveryRequired ( String jarUrl ) { boolean isValidBeanArchive = beanArchiveJarNames . contains ( jarUrl ) ; return isValidBeanArchive ; } public boolean packageDiscoveryRequired ( String packageName ) { return true ; } public boolean rangeDiscoveryRequired ( DiscoveryRange discoveryRange ) { return discoveryRange . equals ( DiscoveryRange . BUNDLE_CLASSPATH ) ; } } ) ; Set < String > acceptedClassNames = bundleClassFinder . find ( ) ; for ( String clsName : acceptedClassNames ) { try { Class < ? > cls = mainBundle . loadClass ( clsName ) ; classAnnotations . put ( clsName , collectAnnotations ( cls ) ) ; beanClasses . add ( cls ) ; } catch ( Exception e ) { logger . info ( "cannot load class from bundle: " + clsName ) ; } } } private Set < String > collectAnnotations ( Class < ? > cls ) { Set < String > annotations = new HashSet < String > ( ) ; addAnnotations ( annotations , cls . getAnnotations ( ) ) ; Constructor [ ] constructors = cls . getDeclaredConstructors ( ) ; for ( Constructor c : constructors ) { addAnnotations ( annotations , c . getAnnotations ( ) ) ; } Field [ ] fields = cls . getDeclaredFields ( ) ; for ( Field f : fields ) { addAnnotations ( annotations , f . getAnnotations ( ) ) ; } Method [ ] methods = cls . getDeclaredMethods ( ) ; for ( Method m : methods ) { addAnnotations ( annotations , m . getAnnotations ( ) ) ; Annotation [ ] [ ] paramsAnns = m . getParameterAnnotations ( ) ; for ( Annotation [ ] pAnns : paramsAnns ) { addAnnotations ( annotations , pAnns ) ; } } return annotations ; } private void addAnnotations ( Set < String > annStrings , Annotation [ ] annotations ) { for ( Annotation ann : annotations ) { annStrings . add ( ann . getClass ( ) . getSimpleName ( ) ) ; } } private void findBeansXml ( Bundle mainBundle , PackageAdmin packageAdmin ) throws Exception { BundleResourceFinder brfXmlJar = new BundleResourceFinder ( packageAdmin , mainBundle , "" , META_INF_BEANS_XML ) ; BundleResourceFinder . ResourceFinderCallback rfCallback = new BundleResourceFinder . ResourceFinderCallback ( ) { public void foundInDirectory ( Bundle bundle , String basePath , URL url ) throws Exception { logger . info ( "adding the following beans.xml URL: " + url ) ; beanXMLs . add ( url ) ; } public void foundInJar ( Bundle bundle , String jarName , ZipEntry entry , InputStream in ) throws Exception { URL jarURL = bundle . getEntry ( jarName ) ; logger . info ( "adding the following beans.xml URL: " + jarURL . toExternalForm ( ) ) ; beanXMLs . add ( jarURL ) ; beanArchiveJarNames . add ( jarName ) ; } } ; brfXmlJar . find ( rfCallback ) ; Enumeration < URL > urls = mainBundle . findEntries ( "" , "beans.xml" , true ) ; boolean webBeansXmlFound = false ; while ( urls != null && urls . hasMoreElements ( ) ) { URL webBeansXml = urls . nextElement ( ) ; if ( ! webBeansXml . toExternalForm ( ) . endsWith ( "/" + WEB_INF_BEANS_XML ) ) { continue ; } if ( webBeansXmlFound ) { throw new WebBeansDeploymentException ( "found more than WEB-INF/beans.xml file!" + webBeansXml ) ; } logger . info ( "adding the following WEB-INF/beans.xml URL: " + webBeansXml ) ; beanXMLs . add ( webBeansXml ) ; webBeansXmlFound = true ; } } public Set < URL > getBeanXmls ( ) { return beanXMLs ; } public Set < Class < ? > > getBeanClasses ( ) { return beanClasses ; } public Set < String > getAllAnnotations ( String className ) { return classAnnotations . get ( className ) ; } public BDABeansXmlScanner getBDABeansXmlScanner ( ) { return null ; } public boolean isBDABeansXmlScanningEnabled ( ) { return false ; } }